/-- A3 positivity: `0 < e_P(X) < 1` holds `P_X`-a.s.
@realizes e_P(a.s. 0 < propensity x ∧ propensity x < 1) -/
def Positivity (P : ObservedLaw 𝒳) : Prop :=
  ∀ᵐ x ∂P.PX, 0 < P.propensity x ∧ P.propensity x < 1

