/-- A8 optimum-in-class: `π_⋆ ∈ Π`. -/
def OptimalInClass (P : ObservedLaw 𝒳) (policySet : Set (Policy 𝒳)) : Prop :=
  lawOptimalPolicy P ∈ policySet

